/* ‚ïê‚ïê‚ïê TINY COMPONENTS ‚ïê‚ïê‚ïê */
const SB=({p,nu,n,h=8})=><div style={{display:"flex",borderRadius:99,overflow:"hidden",height:h,width:"100%"}}><div style={{width:`${p}%`,background:"var(--pos)"}}/><div style={{width:`${nu}%`,background:"var(--tx3)"}}/><div style={{width:`${n}%`,background:"var(--neg)"}}/></div>;
const Bg=({children,c="var(--teal)",bg="var(--tealbg)"})=><span className="badge" style={{background:bg,color:c}}>{children}</span>;
const St=({n=5})=><span style={{display:"inline-flex",gap:1}}>{Array.from({length:n},(_,i)=><I key={i} name="star" size={14}/>)}</span>;
const Dot=({v})=><span style={{width:10,height:10,borderRadius:"50%",background:v>=70?"var(--pos)":v>=50?"var(--warn)":"var(--neg)",display:"inline-block",marginRight:6}}/>;
const Donut=({data,sz=160})=>{const t=Object.values(data).reduce((a,b)=>a+b,0);const cs={positive:"#059669",neutral:"#94A3B8",negative:"#DC2626",mixed:"#D97706"};let cu=0;const sg=Object.entries(data).map(([k,v])=>{const s=cu;cu+=(v/t)*360;const r=60,sr=(s-90)*Math.PI/180,er=(cu-90)*Math.PI/180;return <path key={k} d={`M80,80 L${80+r*Math.cos(sr)},${80+r*Math.sin(sr)} A${r},${r} 0 ${v/t>.5?1:0},1 ${80+r*Math.cos(er)},${80+r*Math.sin(er)} Z`} fill={cs[k]}/>});return <svg viewBox="0 0 160 160" width={sz} height={sz}>{sg}<circle cx="80" cy="80" r="38" fill="var(--bg2)"/><text x="80" y="75" textAnchor="middle" fontSize="28" fontWeight="700" fill="var(--tx)">{Math.round((data.positive/t)*100)}</text><text x="80" y="93" textAnchor="middle" fontSize="10" fill="var(--tx2)">SCORE</text></svg>};
const Toast=({msg,type="success",onClose})=>{useEffect(()=>{const t=setTimeout(onClose,3000);return()=>clearTimeout(t)},[]);const s={success:{bg:"var(--posbg)",c:"var(--pos)"},error:{bg:"var(--negbg)",c:"var(--neg)"},info:{bg:"var(--navybg)",c:"var(--navy)"}}[type];return <div style={{position:"fixed",bottom:24,right:24,zIndex:9999,background:s.bg,color:s.c,borderRadius:10,padding:"12px 20px",fontSize:14,fontWeight:500,boxShadow:"0 8px 24px rgba(0,0,0,0.15)",display:"flex",alignItems:"center",gap:10,maxWidth:360}}>{msg}<span onClick={onClose} style={{cursor:"pointer",opacity:.5,marginLeft:8}}>√ó</span></div>};
const Modal=({title,children,onClose})=><div onClick={onClose} style={{position:"fixed",inset:0,zIndex:9000,background:"rgba(0,0,0,0.5)",backdropFilter:"blur(4px)",display:"flex",alignItems:"center",justifyContent:"center",padding:24}}><div onClick={e=>e.stopPropagation()} className="card" style={{padding:"28px 32px",width:"100%",maxWidth:480,boxShadow:"0 20px 60px rgba(0,0,0,0.2)",maxHeight:"90vh",overflow:"auto"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h3 style={{fontSize:18,fontWeight:600}}>{title}</h3><span onClick={onClose} style={{cursor:"pointer",color:"var(--tx3)",fontSize:20}}>√ó</span></div>{children}</div></div>;
const SC={critical:{bg:"var(--negbg)",c:"var(--neg)"},high:{bg:"var(--warnbg)",c:"var(--coral)"},medium:{bg:"var(--warnbg)",c:"var(--warn)"},low:{bg:"var(--posbg)",c:"var(--pos)"}};
const PC={P1:{bg:"var(--negbg)",c:"var(--neg)"},P2:{bg:"var(--warnbg)",c:"var(--coral)"},P3:{bg:"var(--navybg)",c:"var(--navy)"}};
const Spin=()=><><div style={{width:48,height:48,border:"4px solid var(--bd)",borderTopColor:"var(--teal)",borderRadius:"50%",animation:"spin 1s linear infinite",margin:"0 auto 20px"}}/><style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style></>;

/* ‚ïê‚ïê‚ïê SHARED ANALYSIS RESULTS ‚ïê‚ïê‚ïê */
const AnalysisResults=({compact,nav,show})=>{const a=ANA;return <div>
  <div style={{background:"var(--tealbg)",borderLeft:"4px solid var(--teal)",borderRadius:12,padding:compact?20:24,marginBottom:16}}><div style={{fontWeight:600,fontSize:compact?14:15,color:"var(--teal)",marginBottom:6}}>Executive Summary</div><p style={{fontSize:14,lineHeight:1.7}}>{a.summary}</p></div>
  <div className="grid-2" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:16}}>
    <div className="card" style={{padding:20}}><div style={{fontWeight:600,fontSize:14,marginBottom:12}}>Sentiment</div><div style={{display:"flex",alignItems:"center",gap:16}}><Donut data={a.sent} sz={compact?100:130}/><div style={{flex:1}}>{[["Positive",a.sent.positive,"var(--pos)"],["Neutral",a.sent.neutral,"var(--tx3)"],["Negative",a.sent.negative,"var(--neg)"],["Mixed",a.sent.mixed,"var(--warn)"]].map(([l,v,c])=><div key={l} style={{display:"flex",justifyContent:"space-between",marginBottom:5}}><div style={{display:"flex",alignItems:"center",gap:5}}><span style={{width:8,height:8,borderRadius:2,background:c}}/><span style={{fontSize:13,color:"var(--tx2)"}}>{l}</span></div><span style={{fontWeight:600,fontSize:13,color:c}}>{v}%</span></div>)}</div></div><div style={{marginTop:10}}><SB p={a.sent.positive} nu={a.sent.neutral} n={a.sent.negative} h={10}/></div></div>
    <div className="card" style={{padding:20}}><div style={{display:"flex",alignItems:"center",gap:6,marginBottom:12}}><I name="warn" size={16} color="var(--neg)"/><span style={{fontWeight:600,fontSize:14}}>Top Issues</span></div>{a.complaints.slice(0,compact?3:4).map(c=><div key={c.rank} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 0",borderBottom:"1px solid var(--bd)"}}><span style={{fontSize:18,fontWeight:700,color:"var(--tx3)",width:24}}>#{c.rank}</span><div style={{flex:1}}><div style={{fontSize:13,fontWeight:600,marginBottom:2}}>{c.title}</div><div style={{fontSize:12,color:"var(--tx3)"}}>{c.freq} ({c.pct}%)</div></div><Bg c={SC[c.sev].c} bg={SC[c.sev].bg}>{c.sev}</Bg></div>)}</div>
  </div>
  <div className="grid-2" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:16}}>
    <div className="card" style={{padding:20}}><div style={{display:"flex",alignItems:"center",gap:6,marginBottom:12}}><span>üí™</span><span style={{fontWeight:600,fontSize:14}}>Strengths</span></div>{a.praises.map((p,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 0",borderBottom:i<a.praises.length-1?"1px solid var(--bd)":"none"}}><div style={{width:8,height:8,borderRadius:"50%",background:"var(--pos)",flexShrink:0}}/><div style={{flex:1}}><div style={{fontSize:13,fontWeight:500}}>{p.title}</div><div style={{fontSize:12,color:"var(--tx3)"}}>{p.freq} ({p.pct}%)</div></div></div>)}</div>
    <div className="card" style={{padding:20}}><div style={{display:"flex",alignItems:"center",gap:6,marginBottom:12}}><I name="bulb" size={16} color="var(--warn)"/><span style={{fontWeight:600,fontSize:14}}>Feature Requests</span></div>{a.features.map((f,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 0",borderBottom:i<a.features.length-1?"1px solid var(--bd)":"none"}}><div style={{flex:1}}><div style={{fontSize:13,fontWeight:500}}>{f.title}</div><div style={{fontSize:12,color:"var(--tx3)"}}>{f.demand} requests</div></div><Bg c={f.urg==="high"?"var(--neg)":"var(--warn)"} bg={f.urg==="high"?"var(--negbg)":"var(--warnbg)"}>{f.urg}</Bg></div>)}</div>
  </div>
  <div className="card" style={{padding:20,marginBottom:16}}><div style={{display:"flex",alignItems:"center",gap:6,marginBottom:12}}><I name="tgt" size={16} color="var(--coral)"/><span style={{fontWeight:600,fontSize:14}}>Recommended Actions</span></div>{a.actions.map((it,i)=><div key={i} style={{display:"flex",alignItems:"flex-start",gap:10,padding:"10px 0",borderBottom:i<a.actions.length-1?"1px solid var(--bd)":"none"}}><Bg c={PC[it.pri].c} bg={PC[it.pri].bg}>{it.pri}</Bg><div style={{flex:1}}><div style={{fontSize:13,fontWeight:600,marginBottom:2}}>{it.title}</div><div style={{fontSize:12,color:"var(--tx2)"}}>{it.why}</div><div style={{display:"flex",gap:12,fontSize:11,color:"var(--tx3)",marginTop:4}}><span>Effort: <strong style={{color:"var(--tx2)"}}>{it.effort}</strong></span><span>Impact: <strong style={{color:"var(--pos)"}}>{it.impact}</strong></span></div></div></div>)}</div>
  {!compact&&<div className="card" style={{padding:24}}><div style={{fontWeight:600,fontSize:16,marginBottom:16}}>Rating Distribution</div>{[5,4,3,2,1].map(s=>{const c=a.ratings[s],t=Object.values(a.ratings).reduce((a,b)=>a+b,0);return <div key={s} style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}><span style={{fontSize:13,width:24,textAlign:"right"}}>{s}‚òÖ</span><div style={{flex:1,height:10,background:"var(--bd)",borderRadius:5}}><div style={{height:"100%",background:s>=4?"var(--pos)":s===3?"var(--warn)":"var(--neg)",borderRadius:5,width:`${(c/t)*100}%`}}/></div><span style={{fontSize:12,color:"var(--tx2)",width:28}}>{c}</span></div>})}</div>}
</div>};

