    <div style={{marginBottom:16}}><label style={{fontSize:13,fontWeight:500,color:"var(--tx2)",display:"block",marginBottom:4}}>Email</label><div style={{display:"flex",alignItems:"center",border:"1px solid var(--bd2)",borderRadius:8,padding:"0 12px",background:"var(--bg2)"}}><I name="mail" size={16} color="var(--tx3)"/><input type="email" placeholder="you@company.com" style={{border:"none",padding:"10px 8px",flex:1}}/></div></div>
    {type!=="forgot"&&<div style={{marginBottom:20}}><label style={{fontSize:13,fontWeight:500,color:"var(--tx2)",display:"block",marginBottom:4}}>Password</label><div style={{display:"flex",alignItems:"center",border:"1px solid var(--bd2)",borderRadius:8,padding:"0 12px",background:"var(--bg2)"}}><I name="lock" size={16} color="var(--tx3)"/><input type="password" placeholder="‚Ä¢‚Ä¢‚Ä¢‚Ä¢‚Ä¢‚Ä¢‚Ä¢‚Ä¢" style={{border:"none",padding:"10px 8px",flex:1}}/></div>{type==="signup"&&<div style={{height:4,borderRadius:2,background:"var(--bd)",marginTop:8}}><div style={{height:"100%",borderRadius:2,background:"var(--warn)",width:"60%"}}/></div>}</div>}
    {type==="login"&&<div style={{display:"flex",justifyContent:"space-between",marginBottom:20,fontSize:13}}><label style={{display:"flex",alignItems:"center",gap:6,color:"var(--tx2)",cursor:"pointer"}}><input type="checkbox"/> Remember me</label><span style={{color:"var(--navy)",cursor:"pointer",fontWeight:500}} onClick={()=>nav("forgot")}>Forgot password?</span></div>}
    <button className="btn btn-navy" style={{width:"100%",marginBottom:16}} onClick={()=>type==="forgot"?setSent(true):nav("dashboard")}>{type==="signup"?"Create Account":type==="login"?"Log In":"Send Reset Link"}</button>
    {type!=="forgot"&&<><div style={{textAlign:"center",fontSize:13,color:"var(--tx3)",margin:"16px 0"}}>or continue with</div><button className="btn btn-outline" style={{width:"100%"}} onClick={()=>nav("dashboard")}>Google</button></>}
